const vscode = require("vscode");
const { spawn } = require("child_process");
const os = require("os");
const http = require("http");
const fs = require("fs");
const path = require("path");

// Pick a safe Ollama context length for this machine's RAM. A 12B (~8GB) plus the
// KV cache must fit unified memory or it swaps and the agent "stops responding".
function ollamaContextLength() {
  const gb = os.totalmem() / 1e9;
  return gb >= 32 ? "32768" : gb >= 16 ? "16384" : "8192";
}

function getWorkspaceRoot() {
  const folders = vscode.workspace.workspaceFolders;
  return folders && folders[0] ? folders[0].uri.fsPath : null;
}

function isOllamaUp(callback) {
  const req = http.get("http://127.0.0.1:11434/api/tags", { timeout: 1000 }, (res) => {
    res.resume();
    callback(res.statusCode === 200);
  });
  req.on("timeout", () => req.destroy());
  req.on("error", () => callback(false));
}

let spawnedOllamaProcess = null;

// Start Ollama (warm model, RAM-safe context) if it isn't already running, then cb().
function ensureOllamaRunning(callback) {
  isOllamaUp((up) => {
    if (up) return callback(null);
    spawnedOllamaProcess = spawn("ollama", ["serve"], {
      env: {
        ...process.env,
        OLLAMA_CONTEXT_LENGTH: ollamaContextLength(),
        OLLAMA_KEEP_ALIVE: "30m",
        OLLAMA_FLASH_ATTENTION: "1", // required to enable KV-cache quantization
        OLLAMA_KV_CACHE_TYPE: "q8_0", // halve KV-cache RAM → less swap on a 16k ctx, ~no quality loss
      },
      detached: true,
      stdio: "ignore",
    });
    spawnedOllamaProcess.unref();
    let tries = 0;
    const timer = setInterval(() => {
      tries++;
      isOllamaUp((ready) => {
        if (ready) {
          clearInterval(timer);
          callback(null);
        } else if (tries > 20) {
          clearInterval(timer);
          callback(new Error("Impossibile avviare il server Ollama. Verifica l'installazione."));
        }
      });
    }, 1000);
  });
}

// Fire-and-forget: load the model into memory now so the user's first turn doesn't
// pay the cold-load (~30-60s for a 12B). keep_alive matches the server keep-warm.
function warmModel(model) {
  const body = JSON.stringify({ model, prompt: " ", stream: false, keep_alive: "30m", options: { num_predict: 1 } });
  const req = http.request(
    { hostname: "127.0.0.1", port: 11434, path: "/api/generate", method: "POST",
      headers: { "Content-Type": "application/json", "Content-Length": Buffer.byteLength(body) }, timeout: 120000 },
    (res) => res.resume()
  );
  req.on("error", () => {});
  req.on("timeout", () => req.destroy());
  req.write(body); req.end();
}

function stopOllama() {
  if (spawnedOllamaProcess) {
    try { spawnedOllamaProcess.kill(); } catch (_) {}
    spawnedOllamaProcess = null;
  }
  spawn("pkill", ["-f", "ollama serve"]);
}

// Re-apply the local Hermes thinking/sampling patch before launching. `hermes
// update` overwrites the custom-provider plugin, dropping our reasoning toggle +
// temperature defaults. Running the idempotent reapply script here means a fresh
// launch self-heals the patch — the new TUI process loads it at import, so the
// user never has to remember a manual re-apply or "restart to activate". No-op
// (~instant) if already patched; skipped silently if the repo script isn't found
// (e.g. extension used outside this workspace).
function reapplyHermesPatch(root, callback) {
  const candidates = [
    path.join(root, "scripts", "reapply-thinking-patch.sh"),
    path.join(root, "pocket-llm", "scripts", "reapply-thinking-patch.sh"),
  ];
  const script = candidates.find((p) => fs.existsSync(p));
  if (!script) return callback();
  const proc = spawn("bash", [script], { stdio: "ignore" });
  proc.on("error", () => callback()); // never block the launch on a patch failure
  proc.on("close", () => callback());
}

// Open Hermes' modern TUI in a terminal docked in the EDITOR area beside the
// current editor (a parallel column, not the bottom panel, not a custom webview).
function openHermesTerminal(root) {
  const term = vscode.window.createTerminal({
    name: "Pocket LLM · Hermes",
    cwd: root,
    env: {
      OLLAMA_BASE_URL: "http://127.0.0.1:11434/v1", // local Ollama OpenAI-compatible endpoint
      OLLAMA_API_KEY: "ollama", // dummy key (Ollama ignores it; the OpenAI client wants one)
    },
    location: { viewColumn: vscode.ViewColumn.Beside }, // open as a parallel editor column
  });
  term.show();
  term.sendText("hermes --tui", true); // modern interactive TUI (picker overlays) vs classic REPL
}

// One-click launcher: ensure Ollama is up + warm, then open Hermes' modern TUI
// in a parallel editor column.
function launchHermes() {
  const root = getWorkspaceRoot();
  if (!root) {
    vscode.window.showErrorMessage("Apri una cartella (workspace) per avviare Hermes.");
    return;
  }
  vscode.window.setStatusBarMessage("Pocket LLM: avvio Ollama…", 4000);
  ensureOllamaRunning((err) => {
    if (err) {
      vscode.window.showErrorMessage("Ollama: " + err.message);
      return;
    }
    // Restore the local plugin patch (idempotent) BEFORE opening the TUI, so the
    // fresh Hermes process loads the reasoning toggle + temperature defaults.
    reapplyHermesPatch(root, () => {
      warmModel("gemma4:12b"); // preload so the first Hermes turn is warm
      openHermesTerminal(root);
    });
  });
}

function activate(context) {
  context.subscriptions.push(
    vscode.commands.registerCommand("localAi.launch", launchHermes),
    vscode.commands.registerCommand("localAi.stopServer", () => {
      stopOllama();
      vscode.window.showInformationMessage("Pocket LLM: server Ollama fermato (RAM liberata).");
    })
  );

  const item = vscode.window.createStatusBarItem(vscode.StatusBarAlignment.Left, 99);
  item.text = "$(rocket) Hermes";
  item.tooltip = "Avvia Hermes (Pocket LLM) in una colonna parallela — Ollama + Gemma locale";
  item.command = "localAi.launch";
  item.show();
  context.subscriptions.push(item);
}

function deactivate() {}

module.exports = { activate, deactivate };

