  ensureOllamaRunning((err) => {
    if (err) {
      vscode.window.showErrorMessage("Ollama: " + err.message);
      return;
    }
    // Restore the local plugin patch (idempotent) BEFORE opening the TUI, so the
    // fresh Hermes process loads the reasoning toggle + temperature defaults.
    reapplyHermesPatch(root, () => {
      warmModel("gemma4:12b"); // preload so the first Hermes turn is warm
      openHermesTerminal(root);
    });
  });
}

function activate(context) {
  context.subscriptions.push(
    vscode.commands.registerCommand("localAi.launch", launchHermes),
    vscode.commands.registerCommand("localAi.stopServer", () => {
      stopOllama();
      vscode.window.showInformationMessage("Pocket LLM: server Ollama fermato (RAM liberata).");
    })
  );

  const item = vscode.window.createStatusBarItem(vscode.StatusBarAlignment.Left, 99);
  item.text = "$(rocket) Hermes";
  item.tooltip = "Avvia Hermes (Pocket LLM) in una colonna parallela — Ollama + Gemma locale";
  item.command = "localAi.launch";
  item.show();
  context.subscriptions.push(item);
}

function deactivate() {}

module.exports = { activate, deactivate };

