      tries++;
      isOllamaUp((ready) => {
        if (ready) {
          clearInterval(timer);
          callback(null);
        } else if (tries > 20) {
          clearInterval(timer);
          callback(new Error("Failed to start the Ollama server. Check your installation."));
        }
      });
    }, 1000);
  });
}

